import React, { useState, useEffect } from 'react';
import { NavLink, Link } from 'react-router-dom';
import { Menu, X, Sun, Moon, Github, Linkedin, Mail, Cpu, Terminal, Shield, BarChart3 } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isDark, setIsDark] = useState(true);

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  const navItems = [
    { name: 'Home', path: '/' },
    { name: 'About', path: '/about' },
    { name: 'Portfolio', path: '/portfolio' },
    { name: 'Resume', path: '/resume' },
    { name: 'Certs', path: '/certificates' },
    { name: 'Blog', path: '/blog' },
    { name: 'Contact', path: '/contact' },
  ];

  return (
    <div className="min-h-screen flex flex-col font-sans transition-colors duration-300">
      {/* Navigation */}
      <nav className="sticky top-0 z-50 bg-white/80 dark:bg-slate-950/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <Link to="/" className="flex items-center space-x-2 group">
              <div className="w-10 h-10 bg-primary-600 rounded-lg flex items-center justify-center text-white group-hover:bg-primary-500 transition-colors">
                <Terminal size={24} />
              </div>
              <span className="text-xl font-bold bg-gradient-to-r from-primary-600 to-sky-400 bg-clip-text text-transparent">
                CloudOps.io
              </span>
            </Link>

            {/* Desktop Nav */}
            <div className="hidden md:flex items-center space-x-8">
              {navItems.map((item) => (
                <NavLink
                  key={item.path}
                  to={item.path}
                  className={({ isActive }) =>
                    `text-sm font-medium transition-colors hover:text-primary-500 ${
                      isActive ? 'text-primary-600 dark:text-primary-400' : 'text-slate-600 dark:text-slate-400'
                    }`
                  }
                >
                  {item.name}
                </NavLink>
              ))}
              <button
                onClick={() => setIsDark(!isDark)}
                className="p-2 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
              >
                {isDark ? <Sun size={18} /> : <Moon size={18} />}
              </button>
            </div>

            {/* Mobile Nav Toggle */}
            <div className="md:hidden flex items-center space-x-4">
              <button
                onClick={() => setIsDark(!isDark)}
                className="p-2 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300"
              >
                {isDark ? <Sun size={18} /> : <Moon size={18} />}
              </button>
              <button
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className="text-slate-600 dark:text-slate-400"
              >
                {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMenuOpen && (
          <div className="md:hidden bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 animate-in slide-in-from-top duration-300">
            <div className="px-2 pt-2 pb-3 space-y-1">
              {navItems.map((item) => (
                <NavLink
                  key={item.path}
                  to={item.path}
                  onClick={() => setIsMenuOpen(false)}
                  className={({ isActive }) =>
                    `block px-3 py-2 rounded-md text-base font-medium ${
                      isActive
                        ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400'
                        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-900'
                    }`
                  }
                >
                  {item.name}
                </NavLink>
              ))}
            </div>
          </div>
        )}
      </nav>

      {/* Main Content */}
      <main className="flex-grow">
        {children}
      </main>

      {/* Footer */}
      <footer className="bg-slate-50 dark:bg-slate-950 border-t border-slate-200 dark:border-slate-900 py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-12">
            <div className="col-span-1 md:col-span-2">
              <Link to="/" className="flex items-center space-x-2 mb-4">
                <Terminal className="text-primary-600" size={24} />
                <span className="text-xl font-bold dark:text-white">CloudOps.io</span>
              </Link>
              <p className="text-slate-600 dark:text-slate-400 max-w-sm">
                Engineering resilient, scalable, and automated cloud infrastructure. 
                Focusing on Site Reliability and DevSecOps best practices.
              </p>
              <div className="flex space-x-4 mt-6">
                <a href="#" className="p-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg hover:border-primary-500 text-slate-600 dark:text-slate-400 transition-all">
                  <Github size={20} />
                </a>
                <a href="#" className="p-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg hover:border-primary-500 text-slate-600 dark:text-slate-400 transition-all">
                  <Linkedin size={20} />
                </a>
                <a href="#" className="p-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg hover:border-primary-500 text-slate-600 dark:text-slate-400 transition-all">
                  <Mail size={20} />
                </a>
              </div>
            </div>
            <div>
              <h4 className="text-sm font-bold uppercase tracking-wider text-slate-900 dark:text-white mb-6">Sitemap</h4>
              <ul className="space-y-4">
                {navItems.map((item) => (
                  <li key={item.path}>
                    <Link to={item.path} className="text-slate-600 dark:text-slate-400 hover:text-primary-500 transition-colors">
                      {item.name}
                    </Link>
                  </li>
                ))}
              </ul>
            </div>
            <div>
              <h4 className="text-sm font-bold uppercase tracking-wider text-slate-900 dark:text-white mb-6">Expertise</h4>
              <ul className="space-y-4 text-slate-600 dark:text-slate-400">
                <li className="flex items-center space-x-2">
                   <Cpu size={14} className="text-primary-500" />
                   <span>Cloud Architecture</span>
                </li>
                <li className="flex items-center space-x-2">
                   <Shield size={14} className="text-primary-500" />
                   <span>DevSecOps</span>
                </li>
                <li className="flex items-center space-x-2">
                   <BarChart3 size={14} className="text-primary-500" />
                   <span>SRE & Monitoring</span>
                </li>
              </ul>
            </div>
          </div>
          <div className="mt-12 pt-8 border-t border-slate-200 dark:border-slate-900 text-center">
            <p className="text-slate-500 dark:text-slate-500 text-sm">
              &copy; {new Date().getFullYear()} CloudOps.io. All rights reserved.
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
};

import React, { useState } from 'react';
import { PROJECTS } from '../constants';
import { ExternalLink, Github, Code2, Globe, Database, ShieldAlert } from 'lucide-react';

export const Portfolio: React.FC = () => {
  const [filter, setFilter] = useState('All');
  const categories = ['All', ...Array.from(new Set(PROJECTS.map(p => p.category)))];

  const filteredProjects = filter === 'All' 
    ? PROJECTS 
    : PROJECTS.filter(p => p.category === filter);

  const getCategoryIcon = (cat: string) => {
    switch (cat.toLowerCase()) {
      case 'cloud infrastructure': return <Globe size={16} />;
      case 'devsecops': return <ShieldAlert size={16} />;
      case 'automation': return <Code2 size={16} />;
      default: return <Database size={16} />;
    }
  };

  return (
    <div className="py-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-12">
          <h1 className="text-4xl font-extrabold dark:text-white mb-4">Engineering Showcase</h1>
          <p className="text-xl text-slate-600 dark:text-slate-400 max-w-2xl">
            A deep dive into real-world projects solving complex infrastructure and scaling challenges.
          </p>
        </div>

        {/* Filters */}
        <div className="flex flex-wrap gap-2 mb-12">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
                filter === cat 
                ? 'bg-primary-600 text-white shadow-lg shadow-primary-600/20' 
                : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-800 hover:border-primary-500'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Project Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          {filteredProjects.map((project) => (
            <div key={project.id} className="group flex flex-col bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300">
              <div className="relative aspect-video overflow-hidden">
                <img 
                  src={project.imageUrl} 
                  alt={project.title} 
                  className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                />
                <div className="absolute top-4 left-4">
                   <div className="inline-flex items-center space-x-2 px-3 py-1 rounded-full bg-white/90 dark:bg-slate-900/90 backdrop-blur shadow-sm text-xs font-bold text-slate-900 dark:text-white">
                      {getCategoryIcon(project.category)}
                      <span>{project.category}</span>
                   </div>
                </div>
              </div>

              <div className="p-8 flex flex-col flex-grow">
                <h3 className="text-2xl font-bold dark:text-white mb-4">{project.title}</h3>

                <div className="space-y-6 mb-8 flex-grow">
                  <div>
                    <h4 className="text-xs font-bold uppercase tracking-widest text-primary-600 mb-2">Problem</h4>
                    <p className="text-slate-600 dark:text-slate-400 leading-relaxed">{project.problem}</p>
                  </div>
                  <div>
                    <h4 className="text-xs font-bold uppercase tracking-widest text-primary-600 mb-2">Solution</h4>
                    <p className="text-slate-600 dark:text-slate-400 leading-relaxed">{project.solution}</p>
                  </div>
                  <div className="p-4 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-100 dark:border-slate-800">
                    <h4 className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Architecture</h4>
                    <p className="text-sm font-mono text-slate-600 dark:text-slate-400">{project.architecture}</p>
                  </div>
                </div>

                <div className="flex flex-wrap gap-2 mb-8">
                  {project.technologies.map(tech => (
                    <span key={tech} className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-lg text-xs font-bold text-slate-600 dark:text-slate-400">
                      {tech}
                    </span>
                  ))}
                </div>

                <div className="flex space-x-4 pt-6 border-t border-slate-100 dark:border-slate-800">
                  <a href={project.link} className="flex-1 inline-flex items-center justify-center px-4 py-3 rounded-xl bg-slate-900 dark:bg-slate-800 text-white font-bold hover:bg-slate-800 transition-colors">
                    <Github className="mr-2" size={18} /> Code Repository
                  </a>
                  <a href="#" className="flex-1 inline-flex items-center justify-center px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-800 font-bold dark:text-white hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                    <ExternalLink className="mr-2" size={18} /> Case Study
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import { Layout } from './components/Layout';
import { Home } from './pages/Home';
import { About } from './pages/About';
import { Portfolio } from './pages/Portfolio';
import { Resume } from './pages/Resume';
import { Certificates } from './pages/Certificates';
import { Blog } from './pages/Blog';
import { Contact } from './pages/Contact';

// Scroll to top on route change
const ScrollToTop = () => {
  const { pathname } = useLocation();
  React.useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  return (
    <Router>
      <ScrollToTop />
      <Layout>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/portfolio" element={<Portfolio />} />
          <Route path="/resume" element={<Resume />} />
          <Route path="/certificates" element={<Certificates />} />
          <Route path="/blog" element={<Blog />} />
          <Route path="/contact" element={<Contact />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

