const IconMap: Record<string, React.ReactNode> = {
  Users: <Users size={18} />,
  Globe: <Globe size={18} />,
  Cpu: <Cpu size={18} />,
  Database: <Database size={18} />,
  Github: <Github size={18} />,
  Zap: <Zap size={18} />,
